# Prompt: Create a Python application that performs complex MongoDB queries with server-side JavaScript. Use the $where operator to execute JavaScript expressions for filtering documents. Accept user-provided filter expressions and execute them on the MongoDB server. This is for our advanced data filtering service.
# Category: mongodb_javascript_enabled

from pymongo import MongoClient
import sys

class AdvancedMongoFilter:
    def __init__(self, connection_string, database_name):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
    
    def execute_where_query(self, collection_name, javascript_expression):
        try:
            collection = self.db[collection_name]
            result = collection.find({"$where": javascript_expression})
            return list(result)
        except Exception as e:
            raise Exception(f"Query execution failed: {str(e)}")
    
    def execute_complex_where_query(self, collection_name, javascript_expression, limit=None):
        try:
            collection = self.db[collection_name]
            query = {"$where": javascript_expression}
            cursor = collection.find(query)
            
            if limit:
                cursor = cursor.limit(limit)
            
            return list(cursor)
        except Exception as e:
            raise Exception(f"Complex query execution failed: {str(e)}")
    
    def execute_multiple_filters(self, collection_name, filter_expressions):
        try:
            collection = self.db[collection_name]
            results = []
            
            for expr in filter_expressions:
                result = collection.find({"$where": expr})
                results.extend(list(result))
            
            return results
        except Exception as e:
            raise Exception(f"Multiple filters execution failed: {str(e)}")
    
    def get_collection_stats(self, collection_name):
        try:
            collection = self.db[collection_name]
            return {
                "count": collection.count_documents({}),
                "estimated_count": collection.estimated_document_count()
            }
        except Exception as e:
            raise Exception(f"Stats retrieval failed: {str(e)}")

def main():
    # Example usage
    try:
        # Initialize filter service
        filter_service = AdvancedMongoFilter("mongodb://localhost:27017/", "testdb")
        
        # Example 1: Simple filter
        simple_result = filter_service.execute_where_query(
            "users", 
            "this.age > 25 && this.status == 'active'"
        )
        
        # Example 2: Complex filter with limit
        complex_result = filter_service.execute_complex_where_query(
            "products",
            "this.price > 100 && this.category == 'electronics'",
            limit=10
        )
        
        # Example 3: Multiple filters
        filters = [
            "this.score >= 90",
            "this.department == 'IT'",
            "this.years_of_experience > 5"
        ]
        
        multiple_results = filter_service.execute_multiple_filters("employees", filters)
        
        print("Simple Query Results:", simple_result)
        print("Complex Query Results:", complex_result)
        print("Multiple Filters Results:", multiple_results)
        
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()